diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..d30c92800c6b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2001,7 +2001,6 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     Value *LShr = Builder.CreateLShr(Y, X);
     return new ICmpInst(Pred, LShr, Constant::getNullValue(LShr->getType()));
   }
-
   // (icmp eq/ne (and (add A, Addend), Msk), C)
   //    -> (icmp eq/ne (and A, Msk), (and (sub C, Addend), Msk))
   {
@@ -2017,18 +2016,47 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     }
   }

-  return nullptr;
-}
-
-/// Fold icmp eq/ne (or (xor/sub (X1, X2), xor/sub (X3, X4))), 0.
-static Value *foldICmpOrXorSubChain(ICmpInst &Cmp, BinaryOperator *Or,
-                                    InstCombiner::BuilderTy &Builder) {
-  // Are we using xors or subs to bitwise check for a pair or pairs of
-  // (in)equalities? Convert to a shorter form that has more potential to be
-  // folded even further.
-  // ((X1 ^/- X2) || (X3 ^/- X4)) == 0 --> (X1 == X2) && (X3 == X4)
-  // ((X1 ^/- X2) || (X3 ^/- X4)) != 0 --> (X1 != X2) || (X3 != X4)
-  // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) == 0 -->
+  // We want to transform:
+  // (icmp eq/ne (and (add X, C), C2), 0)
+  // Into:
+  // (icmp eq/ne (and X, C3), 0)
+  {
+    Value *X;
+    const APInt *C_Add, *C_And;
+    if (match(And, m_And(m_OneUse(m_Add(m_Value(X), m_APInt(C_Add))),
+                         m_APInt(C_And))) &&
+        C.isZero()) {
+      ConstantRange XRange = computeConstantRange(X, true, &Cmp);
+      if (!XRange.isFullSet() && !XRange.isEmptySet() &&
+          !XRange.isWrappedSet() &&
+          (XRange.getUpper() - XRange.getLower()).ule(64)) {
+        unsigned BitWidth = X->getType()->getScalarSizeInBits();
+        SmallVector<bool, 64> ValidValues;
+        for (APInt Val = XRange.getLower(); Val != XRange.getUpper(); ++Val) {
+          ValidValues.push_back(((Val + *C_Add) & *C_And).isZero());
+        }
+        for (unsigned m = 0; m < BitWidth; ++m) {
+          APInt M = APInt::getOneBitSet(BitWidth, m);
+          bool Eq0Match = true;
+          bool Ne0Match = true;
+          unsigned j = 0;
+          for (APInt Val = XRange.getLower(); Val != XRange.getUpper(); ++Val) {
+            bool Is0 = (Val & M).isZero();
+            bool Valid = ValidValues[j];
+            if (Is0 != Valid) Eq0Match = false;
+            if (!Is0 != Valid) Ne0Match = false;
+            if (!Eq0Match && !Ne0Match) break;
+            j++;
+          }
+          if (Eq0Match || Ne0Match) {
+            CmpInst::Predicate NewPred = Eq0Match ? CmpInst::ICMP_EQ : CmpInst::ICMP_NE;
+            if (Pred == CmpInst::ICMP_NE)
+              NewPred = CmpInst::getInversePredicate(NewPred);
+            Value *NewAnd = Builder.CreateAnd(X, ConstantInt::get(X->getType(), M));
+            return new ICmpInst(NewPred, NewAnd, ConstantInt::getNullValue(X->getType()));
+          }
+        }
+      }
   // (X1 == X2) && (X3 == X4) && (X5 == X6)
   // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) != 0 -->
   // (X1 != X2) || (X3 != X4) || (X5 != X6)

