  1975 |     auto NewPred =
  1976 |         Pred == CmpInst::ICMP_EQ ? CmpInst::ICMP_UGT : CmpInst::ICMP_ULE;
  1977 |     return new ICmpInst(NewPred, X, SubOne(cast<Constant>(Cmp.getOperand(1))));
  1978 |   }
  1979 | 
